```class Solution {
public:
    bool hasAlternatingBits(int n) {
        int prevBit = n & 1;
        while (n >>= 1) {
            int currBit = n & 1;
            if (prevBit == currBit) return false;
            prevBit = currBit;
        }
        return true;
    }
};```
